# Concrete entity implementations - uses types from types_module
from types_module import Shape, IDrawable, IMeasurable, Color, Point

class Circle(Shape, IDrawable, IMeasurable):
    radius: float
    center: Point

    def __init__(self, name: str, radius: float, center: Point):
        super().__init__(name)
        self.radius = radius
        self.center = center

    @override
    def describe(self) -> str:
        return f"Circle '{self.name}' with radius {self.radius}"

    @override
    def calculate_area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def draw(self) -> str:
        return f"Drawing circle at ({self.center.x}, {self.center.y})"

    property area: float
        get:
            return self.calculate_area()

class Rectangle(Shape, IDrawable, IMeasurable):
    width: float
    height: float
    shape_color: Color

    def __init__(self, name: str, width: float, height: float, shape_color: Color):
        super().__init__(name)
        self.width = width
        self.height = height
        self.shape_color = shape_color

    @override
    def describe(self) -> str:
        return f"Rectangle '{self.name}' {self.width} x {self.height}"

    @override
    def calculate_area(self) -> float:
        return self.width * self.height

    def draw(self) -> str:
        color_name: str = self.get_color_name()
        return f"Drawing {color_name} rectangle"

    property area: float
        get:
            return self.calculate_area()

    def get_color_name(self) -> str:
        match self.shape_color:
            case Color.RED:
                return "red"
            case Color.GREEN:
                return "green"
            case Color.BLUE:
                return "blue"
            case Color.YELLOW:
                return "yellow"
            case _:
                return "unknown"

