# Utility functions for working with shapes
from types_module import Shape, Color

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.calculate_area()
    return total

def count_by_color(shapes: list[Shape], target_color: Color) -> int:
    count: int = 0
    for shape in shapes:
        if shape.name == "red_rectangle" and target_color == Color.RED:
            count += 1
        elif shape.name == "blue_rectangle" and target_color == Color.BLUE:
            count += 1
    return count

def describe_all(shapes: list[Shape]) -> list[str]:
    descriptions: list[str] = []
    for shape in shapes:
        descriptions.append(shape.describe())
    return descriptions
